	originalKey := os.Getenv("JWT_SIGNING_KEY")
	os.Setenv("JWT_SIGNING_KEY", "test-secret-key")
	defer func() { os.Setenv("JWT_SIGNING_KEY", originalKey) }()

	tests := []struct {
